        //             "ro": false,
        //             "s": "ETH-USDC",
        //             "st": "NEW",
        //             "t": "LIMIT",
        //             "tp": "0",
        //             "u": "0.001",
        //             "v": "2"
        //         }
        //     }
        //
        let mut rawOrder: Value = self.safe_dict_k(message.clone(), "o", &[Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        })]);
